#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A, B, C, D, E, F, L, R;
        scanf("%d %d %d", &A, &B, &C);
        scanf("%d %d %d", &D, &E, &F);
        scanf("%d %d", &L, &R);
        double sum = 0;
        for (int x = L; x <= R; x++) {
            double f_x = A * x * x + B * x + C;
            double g_x = D * x * x + E * x + F;
            double h_x = (f_x + g_x) / 2;
            sum += fabs(f_x - h_x) + fabs(g_x - h_x);
        }
        printf("%.0f/%d\n", sum, 1);
    }
    return 0;
}

